import React from 'react';

function Logement() {
    return (
        <div>
            <div className="logement">
                <img src="https://picsum.photos/200/300" alt="" />
            </div>
            <div>
                <h1>Cozy loft on the Canal Saint-Martin</h1>
                <h2>Paris, Île-de-France</h2>
                <p>Cozy</p>
                <p>Canal</p>
                <p>Paris 10</p>
            </div>
        </div>
    );
}

export default Logement;
